(33, 'CUST0008', '6', 'Quote for fdsdfsdfsd - Vantrippers Travel & Tours', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n    <meta charset=\"UTF-8\">\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n    <style>\r\n        body {\r\n            font-family: Arial, sans-serif;\r\n            line-height: 1.6;\r\n            color: #333;\r\n            max-width: 600px;\r\n            margin: 0 auto;\r\n            padding: 20px;\r\n            background-color: #f9f9f9;\r\n        }\r\n        .container {\r\n            background-color: #ffffff;\r\n            border-radius: 8px;\r\n            padding: 25px;\r\n            box-shadow: 0 2px 5px rgba(0,0,0,0.1);\r\n        }\r\n        .logo {\r\n            text-align: center;\r\n            margin-bottom: 25px;\r\n        }\r\n        .logo img {\r\n            max-width: 180px;\r\n            height: auto;\r\n        }\r\n        .quote-info {\r\n            background-color: #f5f5f5;\r\n            border-left: 4px solid #3c8dbc;\r\n            padding: 15px;\r\n            margin-bottom: 20px;\r\n            border-radius: 4px;\r\n        }\r\n        .content {\r\n            margin: 20px 0;\r\n        }\r\n        .signature {\r\n            margin-top: 30px;\r\n            padding-top: 15px;\r\n            border-top: 1px solid #eee;\r\n            font-style: italic;\r\n            color: #555;\r\n        }\r\n        .button {\r\n            display: inline-block;\r\n            background-color: #3c8dbc;\r\n            color: white;\r\n            padding: 10px 20px;\r\n            text-decoration: none;\r\n            border-radius: 4px;\r\n            margin-top: 15px;\r\n        }\r\n        .footer {\r\n            text-align: center;\r\n            margin-top: 30px;\r\n            font-size: 12px;\r\n            color: #777;\r\n        }\r\n    </style>\r\n</head>\r\n<body>\r\n    <div class=\"container\">\r\n        <div class=\"logo\">\r\n            <img src=\"https://vantripperstravelandtours.com/images/main_logo.png\" alt=\"Vantrippers Travel & Tours\" />\r\n        </div>\r\n        \r\n        <div class=\"quote-info\">\r\n            <p><strong>Quote Number:</strong> 6</p>\r\n            <p><strong>Date:</strong> May 21, 2025</p>\r\n            <p><strong>Valid Until:</strong> May 24, 2025</p>\r\n        </div>\r\n        \r\n        <div class=\"content\">\r\n                    <div style=\"font-family: Arial, sans-serif; line-height: 1.6;\">\r\n                    <p style=\"margin: 0 0 0.5em;\">Good Day,</p>\r\n                    <p style=\"margin: 0 0 0.5em;\">\r\n                        Thank you for requesting a quotation for our travel services. Attached to this email, you will find a PDF containing the full details of your personalized package.\r\n                    </p>\r\n                    <p style=\"margin: 0 0 0.5em;\">\r\n                        This quotation is valid for three days from the date of this message. If you would like to confirm your booking, simply reply to this email and we will provide you with payment instructions.\r\n                    </p>\r\n                    <p style=\"margin: 0 0 0.5em;\">\r\n                        If you have any questions, need to make adjustments, or wish to add extra services, please let us know and we will update the quote accordingly.\r\n                    </p>\r\n                    <p style=\"margin: 0 0 0.5em;\">\r\n                        We look forward to helping you create an unforgettable travel experience.\r\n                    </p>\r\n                    <p style=\"margin: 0 0 0.5em;\">\r\n                        Warm regards,<br>\r\n                        Vantrippers Travel &amp; Tours \r\n                    </p>\r\n                    </div>\r\n                    </div>\r\n        \r\n        <div class=\"signature\">\r\n            <p>Best regards,<br>\r\n            Vantrippers Travel & Tours<br>\r\n            vantripperstravelandtoursmain@gmail.com<br>\r\n            0976-476-4187</p>\r\n        </div>\r\n        \r\n        <div style=\"text-align: center; margin-top: 20px;\">\r\n            <a href=\"https://www.vantrippers.com/payments\" class=\"button\">Make a Payment</a>\r\n        </div>\r\n    </div>\r\n    \r\n    <div class=\"footer\">\r\n        <p>© 2025 Vantrippers Travel & Tours. All rights reserved.</p>\r\n        <p>HMC Building Unit 5, Arnaldo Hiway Brgy. San Francisco General Trias, Cavite</p>\r\n    </div>\r\n</body>\r\n</html>', 'QUOTE #6\nDate: May 21, 2025\nValid Until: May 24, 2025\n\n\r\n                    \r\n                    Good Day,\r\n                    \r\n                        Thank you for requesting a quotation for our travel services. Attached to this email, you will find a PDF containing the full details of your personalized package.\r\n                    \r\n                    \r\n                        This quotation is valid for three days from the date of this message. If you would like to confirm your booking, simply reply to this email and we will provide you with payment instructions.\r\n                    \r\n                    \r\n                        If you have any questions, need to make adjustments, or wish to add extra services, please let us know and we will update the quote accordingly.\r\n                    \r\n                    \r\n                        We look forward to helping you create an unforgettable travel experience.\r\n                    \r\n                    \r\n                        Warm regards,\r\n                        Vantrippers Travel &amp; Tours \r\n                    \r\n                    \r\n                    \n\nBest regards,\nVantrippers Travel & Tours\nvantripperstravelandtoursmain@gmail.com\n0976-476-4187\n\nFor payments, please visit: https://www.vantrippers.com/payments', '2025-05-21 12:23:53', 'sent', '', '', '', 'markguanmontilla@gmail.com', 'quote_6.pdf', 'C:\\Users\\newpo\\AppData\\Local\\Temp\\quoB38C.tmp');
