(49, 'CUST_0012', '10', 'Invoice #: 10 - Vantrippers Travel and Tour', '<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body><p>Dear Shan,</p>\r\n                                        <p>Thank you for your interest in our <strong>ILOCOS-LA UNION 3D2N 30+2(XL)</strong>.<br>\r\n                                    We’re excited to help you plan your upcoming trip! Please find below the detailed quote for your requested travel dates:</p>\r\n                                    <p> Please visit the following link and complete the form: <a href=\"http://localhost/vantrippers/admin/exclusive_form.php\" target=\"_blank\">Exclusive Terms &amp; Condition</a></p><br><p> Please visit the following link and complete the form: <a href=\"http://localhost/vantrippers/admin/joiners_form.php\" class=\"attachment-reference\">Joiners Terms &amp; Condition</a></p>  <p> Please visit the following link and complete the form: <a href=\"https://localhost/vantrippers/admin/domestic_form.php\" target=\"_blank\" rel=\"noopener noreferrer\">Domestic Terms &amp; Conditions</a></p></body></html>', 'Dear Shan,\r\n                                        Thank you for your interest in our ILOCOS-LA UNION 3D2N 30+2(XL).\r\n                                    We’re excited to help you plan your upcoming trip! Please find below the detailed quote for your requested travel dates:\r\n                                     Please visit the following link and complete the form: Exclusive Terms &amp; Condition Please visit the following link and complete the form: Joiners Terms &amp; Condition   Please visit the following link and complete the form: Domestic Terms &amp; Conditions', '2025-05-29 11:21:14', 'sent', '', '', 'to', 'edishanleetenorio03@gmail.com', 'invoice_10.pdf', 'C:\\Users\\Edishan Lee\\AppData\\Local\\Temp\\inv7C20.tmp'),
