INSERT INTO `terms` (`id`, `category`, `details`, `created_at`) VALUES
(1, 'Luzon Tour Terms', '𝗧𝗘𝗥𝗠𝗦 & 𝗖𝗢𝗡𝗗𝗜𝗧𝗜𝗢𝗡𝗦:\r\n\r\n✹Rates are subject to change without notice unless the down payment has been made.\r\n\r\n✹Hotel accommodation is subject to availability, which may change over time. We cannot guarantee a room until your down payment is received. Your hotel will only be booked once the down payment has been made.\r\n\r\n✹For guaranteed booking, a reservation/downpayent of 1,000 per person is required. The remaining balance  will be collected on the departure date. \r\n~ MODE OF PAYMENT:  BPI, BDO, GCASH \r\n\r\n✹Strictly NO cancellation, non refundable.\r\n\r\n𝗣𝗟𝗘𝗔𝗦𝗘 𝗕𝗘 𝗔𝗗𝗩𝗜𝗦𝗘𝗗:\r\n✹ This quote is based on the availability of the specified accommodation bellow. If it happens to be fully booked, we will provide an alternative another quotation based on a different accommodation, which may affect the rates per person. Additionally, the inclusion of breakfast may vary depending on whether the alternative accommodation offers breakfast offerings. To secure the same rates and accommodation, we highly recommend booking early.\r\n\r\n✹ Please note that the rates provided here are not fixed and do not apply during Special Holidays, Long Weekends, Peak Season, December, and Holy Week. Rates are subject to change without prior notice.\r\n\r\n✹ Additionally, the rates do not include taxes. If you require a service invoice, an additional 12% VAT will be applied based on the total amount. However, if you only request a carbonized Acknowledgment Receipt, we can issue it free of charge. Please be aware that any shipping costs for receipts will be the responsibility of the client.\r\n\r\n Call us if you have any questions: 📞0976-4764187 or call us here on messenger simply click the phone icon 📞 above on the right side! \r\n\r\n📧 or email us at book@vantripperstravelandtour.com\r\n\r\n\r\n🌐Check out our FB Page for more details: https://www.facebook.com/Vantrippers.ph\r\n\r\nWe are legit Travel Agency with:\r\n✔️Complete and Updated Business Permits\r\n✔️With Physical Office: Visit us at HMC Building Unit 5 Brooke Side Lane, San Francisco Gen. Trias, Cavite.\r\n✔️D.O.T Approved Travel Agency with Accreditation: DOT-R4A-TTA-01919-2024 \r\n✔️Our Bank Accounts with BDO and BPI are all under the name of our Travel Agency: Vantrippers Travel and Tours\r\n✔️We accept Credit Card Payment thru PayMaya secured Payment Link with 5% bank charge', '2025-04-30 02:26:18'),
(2, 'Domestic w/ Airfare', 'DOMESTIC WITH AIRFARE\r\n𝗧𝗘𝗥𝗠𝗦 & 𝗖𝗢𝗡𝗗𝗜𝗧𝗜𝗢𝗡𝗦:\r\n✹Rates are subject to change without notice unless the down payment has been made.\r\n✹Hotel accommodation is subject to availability, which may change over time. We cannot guarantee a room until your down payment is received. Your hotel will only be booked once the down payment has been made.\r\n✹For guaranteed booking, a reservation/downpayent of 75% per person is required. The remaining balance should be paid via our bank accounts or GCash at least 3 days before the travel dates. \r\n✹Strictly NO cancellation, non refundable non-rebookable.\r\n\r\n𝗣𝗟𝗘𝗔𝗦𝗘 𝗕𝗘 𝗔𝗗𝗩𝗜𝗦𝗘𝗗:\r\n✹ Please note that the rates provided here are not fixed and do not apply during Special Holidays, Long Weekends, Peak Season, December, and Holy Week. Rates are subject to change without prior notice, including adjustments based on fluctuations in airfare. The rates in this quote are based on regular plane tickets, not promotional fares.\r\n\r\n✹ Additionally, the rates do not include taxes. If you require a service invoice, an additional 12% VAT will be applied based on the total amount. However, if you only request a carbonized Acknowledgment Receipt, we can issue it free of charge. Please be aware that any shipping costs for receipts will be the responsibility of the client.\r\n\r\n Call us if you have any questions: 📞0976-4764187 or call us here on messenger simply click the phone icon 📞 above on the right side! \r\n📧 or email us at book@vantripperstravelandtour.com\r\n\r\n🌐Check out our FB Page for more details: https://www.facebook.com/Vantrippers.ph\r\n\r\n📩Shoot us a message: m.me/vantrippers.ph', '2025-04-30 02:26:54'),
(3, 'Domestic without Airfare', '𝗧𝗘𝗥𝗠𝗦 & 𝗖𝗢𝗡𝗗𝗜𝗧𝗜𝗢𝗡𝗦:\r\n✹Rates are subject to change without notice unless the down payment has been made.\r\n✹Hotel accommodation is subject to availability, which may change over time. We cannot guarantee a room until your down payment is received. Your hotel will only be booked once the down payment has been made.\r\n✹For guaranteed booking, a reservation/downpayent of 50% per person is required. The remaining balance should be paid via our bank accounts or GCash at least 3 days before the travel dates. \r\n✹Strictly NO cancellation, non refundable non-rebookable \r\n\r\n𝗣𝗟𝗘𝗔𝗦𝗘 𝗕𝗘 𝗔𝗗𝗩𝗜𝗦𝗘𝗗:\r\n✹ Please note that the rates provided here are not fixed and do not apply during  Special Holidays, Long Weekends, Peak Season, December, and Holy Week. Rates are subject to change without prior notice.\r\n\r\n✹ Additionally, the rates do not include taxes. If you require a service invoice, an additional 12% VAT will be applied based on the total amount. However, if you only request a carbonized Acknowledgment Receipt, we can issue it free of charge. Please be aware that any shipping costs for receipts will be the responsibility of the client.\r\n\r\n Call us if you have any questions: 📞0976-4764187 or call us here on messenger simply click the phone icon 📞 above on the right side! \r\n📧 or email us at book@vantripperstravelandtour.com\r\n\r\n🌐Check out our FB Page for more details: https://www.facebook.com/Vantrippers.ph\r\n\r\n📩Shoot us a message: m.me/vantrippers.ph', '2025-04-30 02:27:21'),
(4, 'Peak Season With Airfare', '𝗣𝗔𝗬𝗠𝗘𝗡𝗧 𝗧𝗘𝗥𝗠𝗦:\r\n\r\n➤ For guaranteed booking, a reservation/downpayment of 90% per person is required. The remaining balance should be paid via our bank accounts or GCash at least 3 days before the travel dates. \r\n\r\n➤ The Reservation/downpayment will be deducted to your total rate. Reservation is non-refundable but rebookable.\r\n\r\n𝗣𝗟𝗘𝗔𝗦𝗘 𝗕𝗘 𝗔𝗗𝗩𝗜𝗦𝗘𝗗:\r\n✹ Please note that the rates provided here are not fixed and do not apply during Special Holidays, Long Weekends, Peak Season, December, and Holy Week. Rates are subject to change without prior notice, including adjustments based on fluctuations in airfare. The rates in this quote are based on regular plane tickets, not promotional fares.\r\n\r\n✹ Additionally, the rates do not include taxes. If you require a service invoice, an additional 12% VAT will be applied based on the total amount. However, if you only request a carbonized Acknowledgment Receipt, we can issue it free of charge. Please be aware that any shipping costs for receipts will be the responsibility of the client.\r\n\r\nCall us if you have any questions: 📞0976-4764187 or call us here on messenger simply click the phone icon 📞 above on the right side!\r\n\r\n📧 or email us at book@vantripperstravelandtour.com\r\n\r\n🌐Check out our FB Page for more details: https://www.facebook.com/Vantrippers.ph\r\n\r\n📩Shoot us a message: m.me/vantrippers.ph', '2025-04-30 02:27:50'),
(5, 'Regular Season With Airfare', '𝗣𝗔𝗬𝗠𝗘𝗡𝗧 𝗧𝗘𝗥𝗠𝗦:\r\n\r\n➤ For guaranteed booking, a reservation/downpayment of 90% per person is required. The remaining balance should be paid via our bank accounts or GCash at least 3 days before the travel dates. \r\n\r\n➤ The Reservation/downpayment will be deducted to your total rate. Reservation is non-refundable but rebookable.\r\n\r\n𝗣𝗟𝗘𝗔𝗦𝗘 𝗕𝗘 𝗔𝗗𝗩𝗜𝗦𝗘𝗗:\r\n✹ Please note that the rates provided here are not fixed and do not apply during Special Holidays, Long Weekends, Peak Season, December, and Holy Week. Rates are subject to change without prior notice, including adjustments based on fluctuations in airfare. The rates in this quote are based on regular plane tickets, not promotional fares.\r\n\r\n✹ Additionally, the rates do not include taxes. If you require a service invoice, an additional 12% VAT will be applied based on the total amount. However, if you only request a carbonized Acknowledgment Receipt, we can issue it free of charge. Please be aware that any shipping costs for receipts will be the responsibility of the client.\r\n\r\nCall us if you have any questions: 📞0976-4764187 or call us here on messenger simply click the phone icon 📞 above on the right side!\r\n\r\n📧 or email us at book@vantripperstravelandtour.com\r\n\r\n🌐Check out our FB Page for more details: https://www.facebook.com/Vantrippers.ph\r\n\r\n📩Shoot us a message: m.me/vantrippers.ph', '2025-04-30 06:46:23'),
(6, 'Regular Season Without Airfare', '𝗣𝗔𝗬𝗠𝗘𝗡𝗧 𝗧𝗘𝗥𝗠𝗦:\r\n\r\n➤ For guaranteed booking, a reservation/downpayment of 90% per person is required. The remaining balance should be paid via our bank accounts or GCash at least 3 days before the travel dates. \r\n\r\n➤ The Reservation/downpayment will be deducted to your total rate. Reservation is non-refundable but rebookable.\r\n\r\n𝗣𝗟𝗘𝗔𝗦𝗘 𝗕𝗘 𝗔𝗗𝗩𝗜𝗦𝗘𝗗:\r\n✹ Please note that the rates provided here are not fixed and do not apply during  Special Holidays, Long Weekends, Peak Season, December, and Holy Week. Rates are subject to change without prior notice.\r\n\r\n✹ Additionally, the rates do not include taxes. If you require a service invoice, an additional 12% VAT will be applied based on the total amount. However, if you only request a carbonized Acknowledgment Receipt, we can issue it free of charge. Please be aware that any shipping costs for receipts will be the responsibility of the client.\r\n\r\nCall us if you have any questions: 📞0976-4764187 or call us here on messenger simply click the phone icon 📞 above on the right side!\r\n\r\n📧 or email us at book@vantripperstravelandtour.com\r\n\r\n🌐Check out our FB Page for more details: https://www.facebook.com/Vantrippers.ph', '2025-04-30 07:14:42'),
(7, 'Peak Season Without Airfare', '𝗣𝗔𝗬𝗠𝗘𝗡𝗧 𝗧𝗘𝗥𝗠𝗦:\r\n\r\n➤ For guaranteed booking, a reservation/downpayment of 90% per person is required. The remaining balance should be paid via our bank accounts or GCash at least 3 days before the travel dates. \r\n\r\n➤ The Reservation/downpayment will be deducted to your total rate. Reservation is non-refundable but rebookable.\r\n\r\n𝗣𝗟𝗘𝗔𝗦𝗘 𝗕𝗘 𝗔𝗗𝗩𝗜𝗦𝗘𝗗:\r\n✹ Please note that the rates provided here are not fixed and do not apply during  Special Holidays, Long Weekends, Peak Season, December, and Holy Week. Rates are subject to change without prior notice.\r\n\r\n✹ Additionally, the rates do not include taxes. If you require a service invoice, an additional 12% VAT will be applied based on the total amount. However, if you only request a carbonized Acknowledgment Receipt, we can issue it free of charge. Please be aware that any shipping costs for receipts will be the responsibility of the client.\r\n\r\nCall us if you have any questions: 📞0976-4764187 or call us here on messenger simply click the phone icon 📞 above on the right side!\r\n\r\n📧 or email us at book@vantripperstravelandtour.com\r\n\r\n🌐Check out our FB Page for more details: https://www.facebook.com/Vantrippers.ph\r\n\r\n📩Shoot us a message: m.me/vantrippers.ph', '2025-04-30 07:16:24');

