--
-- Table structure for table `tours`
--

CREATE TABLE `tours` (
  `id` int(11) NOT NULL,
  `tour_reference` varchar(100) DEFAULT NULL,
  `tour_type` enum('domestic','luzon_joiners','luzon_exclusive') NOT NULL,
  `travel_dates` varchar(100) NOT NULL,
  `destination` varchar(255) NOT NULL,
  `days` int(11) NOT NULL,
  `pax` int(11) NOT NULL,
  `lead_guest` varchar(255) NOT NULL,
  `contact` varchar(100) NOT NULL,
  `pickup_details` text DEFAULT NULL,
  `balance` decimal(10,2) DEFAULT NULL,
  `payment_status` enum('Partially Paid','Fully Paid') DEFAULT 'Partially Paid',
  `status` enum('active','completed','cancelled') DEFAULT 'active',
  `customer_id` int(11) DEFAULT NULL,
  `invoice_id` int(11) DEFAULT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- --------------------------------------------------------

--
-- Table structure for table `tour_details`
--

CREATE TABLE `tour_details` (
  `id` int(11) NOT NULL,
  `tour_id` int(11) NOT NULL,
  `accommodation` varchar(255) DEFAULT NULL,
  `room_setup` varchar(255) DEFAULT NULL,
  `booked_accommodation` enum('YES','NO') DEFAULT 'NO',
  `coordinated_supplier` enum('YES','NO') DEFAULT 'NO',
  `hotel_balance` enum('Partially Paid','Settled') DEFAULT NULL,
  `van_details_sent` enum('YES','NO') DEFAULT 'NO',
  `with_coordinator` enum('With','None') DEFAULT 'None',
  `created_at` datetime DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

